import React, { useState, useEffect } from 'react';
import { CheckCircle, Clock, Circle, ArrowLeft, Calendar, DollarSign, Code as CodeIcon, FileText, ExternalLink, Image, X, ChevronLeft, ChevronRight } from 'lucide-react';

const PublicTrackingPage = () => {
  const [project, setProject] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [lightboxOpen, setLightboxOpen] = useState(false);
  const [currentImageIndex, setCurrentImageIndex] = useState(0);
  const [allImages, setAllImages] = useState([]);

  const projectCode = window.location.pathname.split('/track/')[1];

  useEffect(() => { fetchProject(); }, []);

  useEffect(() => {
    if (project?.screenshots) setAllImages(project.screenshots);
  }, [project]);

  const fetchProject = async () => {
    try {
      setLoading(true);
      const response = await fetch(`https://api.devstudio.tech/api/projects/track/${projectCode}`);
      const data = await response.json();
      if (data.success) setProject(data.data);
      else setError('Không tìm thấy dự án với mã này');
    } catch (err) {
      setError('Có lỗi xảy ra khi tải dữ liệu');
    } finally {
      setLoading(false);
    }
  };

  const openLightbox = (index) => { setCurrentImageIndex(index); setLightboxOpen(true); document.body.style.overflow = 'hidden'; };
  const closeLightbox = () => { setLightboxOpen(false); document.body.style.overflow = 'auto'; };
  const nextImage = () => setCurrentImageIndex((p) => (p + 1) % allImages.length);
  const prevImage = () => setCurrentImageIndex((p) => (p - 1 + allImages.length) % allImages.length);

  useEffect(() => {
    const h = (e) => { if (!lightboxOpen) return; if (e.key === 'Escape') closeLightbox(); if (e.key === 'ArrowRight') nextImage(); if (e.key === 'ArrowLeft') prevImage(); };
    window.addEventListener('keydown', h);
    return () => window.removeEventListener('keydown', h);
  }, [lightboxOpen, allImages.length]);

  const getStatusColor = (status) => {
    switch (status.toLowerCase()) {
      case 'completed': return 'bg-emerald-500 text-white';
      case 'in-progress': case 'in progress': return 'bg-blue-500 text-white';
      case 'pending': return 'bg-yellow-400 text-yellow-900';
      case 'on-hold': case 'on hold': return 'bg-orange-400 text-white';
      default: return 'bg-gray-400 text-white';
    }
  };

  const getMilestoneIcon = (status) => {
    switch (status.toLowerCase()) {
      case 'completed': return <CheckCircle className="w-6 h-6 text-emerald-500" />;
      case 'in-progress': case 'in progress': return <Clock className="w-6 h-6 text-blue-500" />;
      default: return <Circle className="w-6 h-6 text-gray-300" />;
    }
  };

  const formatDate = (dateString) => {
    if (!dateString) return 'N/A';
    const date = new Date(dateString);
    if (isNaN(date.getTime())) return 'N/A';
    return date.toLocaleDateString('vi-VN', { year: 'numeric', month: 'long', day: 'numeric' });
  };

  const formatStatus = (status) => {
    const m = { 'in-progress': 'Đang thực hiện', 'on-hold': 'Tạm dừng', 'pending': 'Chờ xử lý', 'completed': 'Hoàn thành', 'cancelled': 'Đã hủy' };
    return m[status.toLowerCase()] || status;
  };

  const formatProjectType = (type) => {
    const m = { 'website': 'Website', 'mobile-app': 'Mobile App', 'web-app': 'Web App', 'ecommerce': 'E-Commerce', 'landing-page': 'Landing Page', 'backend': 'Backend API' };
    return m[type] || type;
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="text-center">
          <div className="animate-spin rounded-full h-16 w-16 border-t-4 border-b-4 border-blue-500 mx-auto mb-4"></div>
          <p className="text-gray-600 text-lg">Đang tải dữ liệu...</p>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center p-4">
        <div className="max-w-md w-full bg-white rounded-2xl shadow-xl border border-gray-200 p-8 text-center">
          <div className="w-20 h-20 bg-red-100 rounded-full flex items-center justify-center mx-auto mb-6">
            <ExternalLink className="w-10 h-10 text-red-500" />
          </div>
          <h2 className="text-2xl font-bold text-gray-900 mb-3">Không tìm thấy dự án</h2>
          <p className="text-gray-500 mb-6">{error}</p>
          <p className="text-sm text-gray-400 mb-6">Mã dự án: <span className="text-blue-600 font-mono font-bold">{projectCode}</span></p>
          <button onClick={() => window.location.href = '/'} className="bg-blue-600 text-white px-8 py-3 rounded-lg font-semibold hover:bg-blue-700 transition">
            Quay về trang chủ
          </button>
        </div>
      </div>
    );
  }

  if (!project) return null;

  const screenshotsByDate = project.screenshots && project.screenshots.length > 0
    ? Object.entries(
        project.screenshots.reduce((groups, img) => {
          const date = img.uploadedAt
            ? new Date(img.uploadedAt).toLocaleDateString('vi-VN', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })
            : 'Không rõ ngày';
          if (!groups[date]) groups[date] = [];
          groups[date].push(img);
          return groups;
        }, {})
      ).sort((a, b) => new Date(b[1][0]?.uploadedAt || 0) - new Date(a[1][0]?.uploadedAt || 0))
    : [];

  return (
    <div className="min-h-screen bg-gray-50 text-gray-900">
      {/* Lightbox */}
      {lightboxOpen && allImages.length > 0 && (
        <div className="fixed inset-0 z-[100] bg-black/90 flex items-center justify-center">
          <button onClick={closeLightbox} className="absolute top-4 right-4 p-2 text-white hover:text-gray-300 transition z-10"><X className="w-8 h-8" /></button>
          <div className="absolute top-4 left-4 text-white text-lg font-medium">{currentImageIndex + 1} / {allImages.length}</div>
          {allImages.length > 1 && <button onClick={prevImage} className="absolute left-4 p-3 bg-white/10 hover:bg-white/20 rounded-full text-white transition"><ChevronLeft className="w-8 h-8" /></button>}
          <div className="max-w-[90vw] max-h-[85vh] flex items-center justify-center">
            <img src={allImages[currentImageIndex]?.url} alt={allImages[currentImageIndex]?.name || 'Screenshot'} className="max-w-full max-h-[85vh] object-contain rounded-lg" />
          </div>
          {allImages.length > 1 && <button onClick={nextImage} className="absolute right-4 p-3 bg-white/10 hover:bg-white/20 rounded-full text-white transition"><ChevronRight className="w-8 h-8" /></button>}
        </div>
      )}

      {/* Header */}
      <header className="bg-white border-b border-gray-200 sticky top-0 z-50 shadow-sm">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4">
          <div className="flex items-center justify-between">
            <button onClick={() => window.location.href = '/'} className="flex items-center space-x-2 text-blue-600 hover:text-blue-800 transition font-semibold">
              <ArrowLeft className="w-5 h-5" />
              <span>Quay lại danh sách</span>
            </button>
            <div className="text-right">
              <p className="text-xs text-gray-400 uppercase tracking-wide">Mã dự án</p>
              <p className="text-lg font-bold text-blue-600 font-mono">{project.projectCode}</p>
            </div>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {/* Project Header Card */}
        <div className="bg-gradient-to-r from-blue-600 via-blue-700 to-indigo-700 rounded-2xl p-8 mb-8 text-white shadow-lg">
          <div className="flex items-start justify-between mb-6">
            <div>
              <h1 className="text-3xl font-black mb-1">{project.title || project.projectName}</h1>
              <p className="text-blue-200 text-lg">{project.description}</p>
            </div>
            <span className={`${getStatusColor(project.status)} px-4 py-2 rounded-full font-semibold text-sm shadow`}>
              {formatStatus(project.status)}
            </span>
          </div>

          {/* Progress */}
          <div className="mb-6">
            <div className="flex justify-between items-center mb-2">
              <span className="text-sm font-medium text-blue-100">Tiến độ dự án</span>
              <span className="text-2xl font-black">{project.progress || 0}%</span>
            </div>
            <div className="w-full bg-blue-900/40 rounded-full h-3 overflow-hidden">
              <div className="h-full bg-white rounded-full transition-all duration-500" style={{ width: `${project.progress || 0}%` }}></div>
            </div>
          </div>

          {/* Client Info */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4 pt-6 border-t border-blue-500/30">
            <div>
              <p className="text-sm text-blue-200 mb-1">Tên khách hàng</p>
              <p className="text-lg font-semibold">{project.clientName}</p>
            </div>
            <div>
              <p className="text-sm text-blue-200 mb-1">Email</p>
              <p className="text-lg font-semibold">{project.clientEmail}</p>
            </div>
          </div>
        </div>

        {/* Two Column Layout */}
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          {/* Left */}
          <div className="lg:col-span-2 space-y-8">
            {/* Milestones */}
            {project.milestones && project.milestones.length > 0 && (
              <div className="bg-white rounded-2xl border border-gray-200 p-6 shadow-sm">
                <h2 className="text-xl font-bold text-gray-900 mb-6 flex items-center">
                  <span className="text-2xl mr-2">📍</span> Milestones
                </h2>
                <div className="space-y-3">
                  {project.milestones.map((milestone, index) => (
                    <div key={index} className="flex items-start space-x-4 p-4 rounded-xl bg-gray-50 border border-gray-100 hover:border-blue-200 transition">
                      <div className="flex-shrink-0 mt-1">{getMilestoneIcon(milestone.status)}</div>
                      <div className="flex-1">
                        <h3 className="text-base font-semibold text-gray-900 mb-1">{milestone.title || milestone.name}</h3>
                        {milestone.description && <p className="text-sm text-gray-500 mb-2">{milestone.description}</p>}
                        <div className="flex items-center space-x-3 text-xs">
                          <span className={`px-2 py-1 rounded-full font-medium ${
                            milestone.status.toLowerCase() === 'completed' ? 'bg-emerald-100 text-emerald-700'
                            : milestone.status.toLowerCase().includes('progress') ? 'bg-blue-100 text-blue-700'
                            : 'bg-gray-100 text-gray-600'
                          }`}>{formatStatus(milestone.status)}</span>
                          {milestone.dueDate && <span className="text-gray-400 flex items-center"><Calendar className="w-3 h-3 mr-1" />{formatDate(milestone.dueDate)}</span>}
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* Daily Updates */}
            {project.dailyUpdates && project.dailyUpdates.length > 0 && (
              <div className="bg-white rounded-2xl border border-gray-200 p-6 shadow-sm">
                <h2 className="text-xl font-bold text-gray-900 mb-6 flex items-center">
                  <span className="text-2xl mr-2">📝</span> Cập nhật hàng ngày
                </h2>
                <div className="space-y-3">
                  {project.dailyUpdates.sort((a, b) => new Date(b.date) - new Date(a.date)).slice(0, 10).map((update, index) => (
                    <div key={index} className="flex items-start space-x-3 p-4 rounded-xl bg-gray-50 border border-gray-100">
                      <div className="flex-shrink-0 w-2 h-2 bg-blue-500 rounded-full mt-2"></div>
                      <div className="flex-1">
                        <p className="text-gray-800 leading-relaxed">{update.update || update.content}</p>
                        <p className="text-xs text-gray-400 mt-2">{formatDate(update.date)}</p>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>

          {/* Right Column */}
          <div className="space-y-6">
            <div className="bg-white rounded-2xl border border-gray-200 p-6 shadow-sm">
              <h3 className="text-lg font-bold text-gray-900 mb-4 flex items-center">
                <FileText className="w-5 h-5 mr-2 text-blue-500" /> Tổng quan
              </h3>
              <div className="space-y-4">
                <div><p className="text-sm text-gray-400 mb-1">Ngày bắt đầu</p><p className="font-semibold text-gray-900">{formatDate(project.startDate)}</p></div>
                <div><p className="text-sm text-gray-400 mb-1">Ngày dự kiến hoàn thành</p><p className="font-semibold text-gray-900">{formatDate(project.estimatedEndDate || project.endDate)}</p></div>
                <div><p className="text-sm text-gray-400 mb-1">Loại dự án</p><p className="font-semibold text-gray-900">{formatProjectType(project.projectType || project.type)}</p></div>
                {project.budget && (
                  <div><p className="text-sm text-gray-400 mb-1">Ngân sách</p><p className="font-semibold text-gray-900 flex items-center"><DollarSign className="w-4 h-4 mr-1" />{project.budget.toLocaleString('vi-VN')} đ</p></div>
                )}
              </div>
            </div>

            {/* Link theo dõi */}
            <div className="bg-blue-50 rounded-2xl border border-blue-200 p-6">
              <h3 className="text-lg font-bold text-gray-900 mb-3">Link theo dõi công khai</h3>
              <div className="bg-white rounded-lg border border-blue-200 p-3 flex items-center justify-between">
                <code className="text-blue-600 text-sm font-mono truncate">/{project.projectCode}</code>
                <button onClick={() => navigator.clipboard.writeText(window.location.href)} className="text-gray-400 hover:text-blue-600 transition ml-2">
                  <ExternalLink className="w-4 h-4" />
                </button>
              </div>
              <p className="text-xs text-gray-400 mt-2">Chia sẻ link này với khách hàng để họ theo dõi tiến độ</p>
            </div>

            {project.technologies && project.technologies.length > 0 && (
              <div className="bg-white rounded-2xl border border-gray-200 p-6 shadow-sm">
                <h3 className="text-lg font-bold text-gray-900 mb-4 flex items-center">
                  <CodeIcon className="w-5 h-5 mr-2 text-blue-500" /> Công nghệ
                </h3>
                <div className="flex flex-wrap gap-2">
                  {project.technologies.map((tech, index) => (
                    <span key={index} className="px-3 py-1.5 bg-blue-50 text-blue-700 rounded-lg text-sm font-medium border border-blue-100">{tech}</span>
                  ))}
                </div>
              </div>
            )}

            {project.notes && (
              <div className="bg-white rounded-2xl border border-gray-200 p-6 shadow-sm">
                <h3 className="text-lg font-bold text-gray-900 mb-3">Ghi chú</h3>
                <p className="text-gray-500 leading-relaxed text-sm">{project.notes}</p>
              </div>
            )}
          </div>
        </div>

        {/* Screenshots */}
        {project.screenshots && project.screenshots.length > 0 && (
          <div className="mt-8 bg-white rounded-2xl border border-gray-200 p-8 shadow-sm">
            <h2 className="text-xl font-bold text-gray-900 mb-8 flex items-center">
              <div className="w-1 h-7 bg-indigo-500 rounded-full mr-3"></div>
              <Image className="w-5 h-5 mr-2 text-indigo-500" />
              Hình ảnh tiến độ
              <span className="ml-3 text-sm font-normal text-gray-400 bg-gray-100 px-3 py-1 rounded-full">{project.screenshots.length} ảnh</span>
            </h2>
            <div className="space-y-10">
              {(() => {
                let imgCounter = 0;
                return screenshotsByDate.map(([date, images]) => {
                  const startIndex = imgCounter;
                  imgCounter += images.length;
                  return (
                    <div key={date} className="border-l-4 border-indigo-400 pl-6">
                      <div className="flex items-center space-x-3 mb-4">
                        <Calendar className="w-5 h-5 text-indigo-500" />
                        <span className="text-lg font-semibold text-gray-900">{date}</span>
                        <span className="text-sm text-gray-400 bg-gray-100 px-3 py-1 rounded-full">{images.length} ảnh</span>
                      </div>
                      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                        {images.map((img, imgIndex) => (
                          <div key={imgIndex} onClick={() => openLightbox(startIndex + imgIndex)} className="cursor-pointer group">
                            <div className="relative overflow-hidden rounded-xl border border-gray-200 hover:border-blue-400 transition-all duration-300 shadow-sm hover:shadow-md">
                              <img src={img.url} alt={img.name || `Screenshot ${imgIndex + 1}`} className="w-full h-52 object-cover group-hover:scale-105 transition-transform duration-300" />
                              <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity duration-300 flex items-center justify-center">
                                <span className="text-white font-medium flex items-center space-x-2 bg-blue-600 px-4 py-2 rounded-lg shadow">
                                  <ExternalLink className="w-4 h-4" />
                                  <span>Xem ảnh</span>
                                </span>
                              </div>
                            </div>
                          </div>
                        ))}
                      </div>
                    </div>
                  );
                });
              })()}
            </div>
          </div>
        )}

        <div className="mt-10 text-center pb-8">
          <p className="text-gray-400 text-sm">Trang này được cập nhật tự động bởi <span className="font-semibold text-gray-600">DevStudio</span></p>
        </div>
      </main>
    </div>
  );
};

export default PublicTrackingPage;
